// Evaluate COI status for every company
const results = $input.first().json;
const companies = results.results || [];
const today = new Date();
today.setHours(0,0,0,0);

const updates = [];
const renewalAlerts = [];
const stats = { active: 0, expired: 0, expiringSoon: 0, missing: 0, noChange: 0 };

for (const co of companies) {
  const props = co.properties || {};
  const id = co.id;
  const name = props.name || 'Unknown';
  const expStr = props.coi_expiration_date;
  const currentStatus = props.coi_status || 'Missing';

  if (!expStr) {
    // No expiry date — mark Missing if not already
    stats.missing++;
    if (currentStatus !== 'Missing') {
      updates.push({ id, name, new_status: 'Missing', reason: 'No COI date on file', days_until_expiry: null });
    }
    continue;
  }

  const expDate = new Date(expStr);
  expDate.setHours(0,0,0,0);
  const msPerDay = 1000 * 60 * 60 * 24;
  const daysUntil = Math.round((expDate - today) / msPerDay);

  let newStatus;
  if (daysUntil < 0) {
    newStatus = 'Expired';
    stats.expired++;
  } else if (daysUntil <= 30) {
    newStatus = 'Active';  // still valid but alert needed
    stats.expiringSoon++;
    renewalAlerts.push({ id, name, days_until_expiry: daysUntil, expiry_date: expStr });
  } else {
    newStatus = 'Active';
    stats.active++;
  }

  if (newStatus !== currentStatus) {
    updates.push({ id, name, new_status: newStatus, old_status: currentStatus, days_until_expiry: daysUntil, expiry_date: expStr });
  } else {
    stats.noChange++;
  }
}

return [{
  json: {
    updates,
    renewal_alerts: renewalAlerts,
    stats,
    total_companies: companies.length,
    has_updates: updates.length > 0,
    has_renewals: renewalAlerts.length > 0,
  }
}];

// Build individual PATCH payloads for each company that needs updating
const data = $input.first().json;
return data.updates.map(u => ({
  json: {
    company_id: u.id,
    company_name: u.name,
    new_status: u.new_status,
    old_status: u.old_status,
    days_until_expiry: u.days_until_expiry,
  }
}));

// Aggregate all items back into a summary
const allItems = $input.all();
const updated = allItems.map(i => `${i.json.properties?.name || i.json.company_name || 'Unknown'} → ${i.json.new_status || '?'}`).join(', ') || 'none';
return [{ json: { updated_companies: updated, count: allItems.length } }];

// Build renewal alert message
const data = $('Evaluate COI Status').first().json;
const alerts = data.renewal_alerts || [];
const lines = alerts.map(a => `${a.name}: expires ${a.expiry_date} (${a.days_until_expiry} days)`);
const urgent = alerts.filter(a => a.days_until_expiry <= 7);
return [{
  json: {
    message: lines.join(' | '),
    priority: urgent.length > 0 ? 'high' : 'default',
    title: urgent.length > 0 ? `COI URGENT: ${urgent.length} expiring this week` : `COI Renewal: ${alerts.length} expiring within 30 days`,
  }
}];

// Build daily COI status summary
const data = $('Evaluate COI Status').first().json;
const s = data.stats;
const msg = `COI Daily: ${data.total_companies} companies | Active: ${s.active} | Expired: ${s.expired} | Expiring 30d: ${s.expiringSoon} | Missing: ${s.missing} | Updated: ${data.updates?.length || 0}`;
const priority = s.expired > 0 ? 'default' : 'min';
return [{ json: { message: msg, priority } }];
